def serialize_to_dict(obj: Any, _seen: set = None) -> Dict[str, Any]:
    """Convert an object to a dict suitable for JSON serialization."""
    if _seen is None:
        _seen = set()
    obj_id = id(obj)
    if obj_id in _seen:
        return '<circular reference>'
    _seen.add(obj_id)
    if hasattr(obj, '__dict__'):
        result = {}
        for key, value in obj.__dict__.items():
            if isinstance(value, (datetime, date)):
                result[key] = value.isoformat()
            elif hasattr(value, '__dict__'):
                result[key] = serialize_to_dict(value, _seen)
            else:
                result[key] = value
        return result
